class CellNamelist(Namelist):
    """Pydantic model for the `Cell` namelist."""


    cell_dynamics: str | None = Field(None, description="Specify the type of dynamics for the cell. For different type of calculation different possibilities are allowed and different default values apply:  CASE ( calculation = 'vc-relax' ) 'none':    no dynamics 'sd':      steepest descent ( not implemented ) 'damp-pr': damped (Beeman) dynamics of the Parrinello-Rahman extended lagrangian 'damp-w':  damped (Beeman) dynamics of the new Wentzcovitch extended lagrangian 'bfgs':    BFGS quasi-newton algorithm (default) ion_dynamics must be 'bfgs' too CASE ( calculation = 'vc-md' ) 'none':    no dynamics 'pr':      (Beeman) molecular dynamics of the Parrinello-Rahman extended lagrangian 'w':       (Beeman) molecular dynamics of the new Wentzcovitch extended lagrangian")
    press: float = Field(0.e0, description="Target pressure [KBar] in a variable-cell md or relaxation run.")
    wmass: float | None = Field(None, description="Fictitious cell mass [amu] for variable-cell simulations (both 'vc-md' and 'vc-relax')")
    cell_factor: float = Field(1.2e0, description="Used in the construction of the pseudopotential tables. It should exceed the maximum linear contraction of the cell during a simulation.")
    press_conv_thr: float | None = Field(None, description="Convergence threshold on the pressure for variable cell relaxation ('vc-relax' : note that the other convergence thresholds for ionic relaxation apply as well).")
    cell_dofree: str = Field("all", description="Select which of the cell parameters should be moved:  all     = all axis and angles are moved x       = only the x axis is moved y       = only the y axis is moved z       = only the z axis is moved xy      = only the x and y axis are moved, angles are unchanged xz      = only the x and z axis are moved, angles are unchanged yz      = only the y and z axis are moved, angles are unchanged xyz     = x, y and z axis are moved, angles are unchanged xyt     = x1, x2, y2 (i.e. lower xy triangle of the 2 vectors) xys     = x1, y1, x2, y2 (i.e. xy square of the 2 vectors) xyzt    = x1, x2, y2, x3, y3, z3 (i.e. lower xyz triangle of the 3 vectors)")


class PhononNamelist(Namelist):
    """Pydantic model for the `Phonon` namelist."""


    modenum: int = Field(0, description="For single-mode phonon calculation : modenum is the index of the irreducible representation (irrep) into which the reducible representation formed by the 3*nat atomic displacements are decomposed in order to perform the phonon calculation.")


class EeNamelist(Namelist):
    """Pydantic model for the `Ee` namelist."""


    which_compensation: str = Field("none", description="dcc' : density counter charge correction. The electrostatic problem is solved in open boundary conditions. At variance with the Makov-Payne approach that only estimates an energy correction here the scf potential is corrected as well. Theory described in: I.Dabo, B.Kozinsky, N.E.Singh-Miller and N.Marzari, 'Electrostatic periodic boundary conditions and real-space corrections', Phys.Rev.B 77, 115139 (2008)")
    ecutcoarse: float = Field(100, description="kinetic energy cutoff defining the grid used for the open boundary correction.")
    mixing_charge_compensation: float = Field(1.0, description="scf mixing parameter for the correcting potential.")
    n_charge_compensation: int = Field(5, description="the correcting potential is updated (mixed) every n_charge_compensation iteration only.")
    comp_thr: float = Field(1.e-4, description="inclusion of dcc correction begins when scf convergence is better than comp_thr.")
    nlev: int = Field(4, description="number of depth levels used by the multigrid solver.")


class PWEspressoInput(EspressoInput):
    """Pydantic model for the input of `pw.x.`"""

    control: ControlNamelist = Field(default_factory=lambda: ControlNamelist())
    system: SystemNamelist = Field(default_factory=lambda: SystemNamelist())
    electrons: ElectronsNamelist = Field(default_factory=lambda: ElectronsNamelist())
    ions: IonsNamelist = Field(default_factory=lambda: IonsNamelist())
    cell: CellNamelist = Field(default_factory=lambda: CellNamelist())
    phonon: PhononNamelist = Field(default_factory=lambda: PhononNamelist())
    ee: EeNamelist = Field(default_factory=lambda: EeNamelist())
